def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError("DESALINEADO")
    return list(zip(a, b))
try:
    zip_strict([1, 2, 3], [10, 20])
except ValueError:
    print("DESALINEADO")
try:
    zip_strict([1, 2], [3, 4])
    print("OK")
except ValueError:
    print("DESALINEADO")

# reconcilia longitudes de columnas de un lote
def reconcile(cols):
    lengths = {k: len(v) for k, v in cols.items()}
    n = next(iter(lengths.values()))
    if any(L != n for L in lengths.values()):
        return {"ok": False, "lengths": lengths}
    return {"ok": True, "n": n}

print(reconcile({"id":[1,2], "st":[1,2]}))
print(reconcile({"id":[1,2,3], "st":[1,2]}))

